{
  "name": "GymRig AI: character-Machine Synchronizer",
  "description": "An advanced tool to analyze character and gym equipment images, generate unified motion parameters in JSON, and visualize the character performing exercises for Blender export.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CharacterParameters {
  physique: string;
  height_estimate_cm: number;
  body_type: string;
  clothing_description: string;
  major_joints_detected: string[];
  rig_complexity: 'low' | 'medium' | 'high';
}

export interface MachineParameters {
  name: string;
  brand: string;
  exercise_type: string;
  mechanical_pivots: string[];
  seat_height_ratio: number;
  handle_type: string;
  resistance_type: string;
}

export interface UnifiedMotionData {
  exercise_name: string;
  starting_pose_rig: any;
  ending_pose_rig: any;
  interaction_points: {
    hands: string;
    feet: string;
    back: string;
  };
  blender_keyframe_data: {
    frame_start: number;
    frame_end: number;
    interpolation: string;
  };
}

export interface AnalysisState {
  character: CharacterParameters | null;
  machine: MachineParameters | null;
  unified: UnifiedMotionData | null;
  generatedImageUrl: string | null;
  isAnalyzing: boolean;
  isGenerating: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";
import { CharacterParameters, MachineParameters, UnifiedMotionData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCharacterImage = async (base64Image: string): Promise<CharacterParameters> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: 'Analyze this character for 3D rigging. Extract physique details, estimated height, body type, clothing, and detectable joints. Return as JSON.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          physique: { type: Type.STRING },
          height_estimate_cm: { type: Type.NUMBER },
          body_type: { type: Type.STRING },
          clothing_description: { type: Type.STRING },
          major_joints_detected: { type: Type.ARRAY, items: { type: Type.STRING } },
          rig_complexity: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['physique', 'height_estimate_cm', 'body_type', 'clothing_description', 'major_joints_detected', 'rig_complexity']
      }
    }
  });

  return JSON.parse(response.text);
};

export const analyzeMachineImage = async (base64Image: string, details?: { name?: string, brand?: string, exercise?: string }): Promise<MachineParameters> => {
  const prompt = `Analyze this gym equipment. Use these provided details if possible: Name: ${details?.name || 'unknown'}, Brand: ${details?.brand || 'unknown'}, Exercise: ${details?.exercise || 'unknown'}. 
  Identify mechanical pivot points, seat ratio, handle types, and resistance mechanisms. Return as JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          exercise_type: { type: Type.STRING },
          mechanical_pivots: { type: Type.ARRAY, items: { type: Type.STRING } },
          seat_height_ratio: { type: Type.NUMBER },
          handle_type: { type: Type.STRING },
          resistance_type: { type: Type.STRING }
        },
        required: ['name', 'brand', 'exercise_type', 'mechanical_pivots', 'seat_height_ratio', 'handle_type', 'resistance_type']
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateUnifiedMotion = async (char: CharacterParameters, mach: MachineParameters): Promise<UnifiedMotionData> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Synthesize a 3D animation sequence. 
    Character: ${JSON.stringify(char)}. 
    Machine: ${JSON.stringify(mach)}. 
    Define interaction points and keyframe-ready data for Blender export. Return as JSON.`,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          exercise_name: { type: Type.STRING },
          starting_pose_rig: { type: Type.OBJECT, properties: {} },
          ending_pose_rig: { type: Type.OBJECT, properties: {} },
          interaction_points: {
            type: Type.OBJECT,
            properties: {
              hands: { type: Type.STRING },
              feet: { type: Type.STRING },
              back: { type: Type.STRING }
            }
          },
          blender_keyframe_data: {
            type: Type.OBJECT,
            properties: {
              frame_start: { type: Type.NUMBER },
              frame_end: { type: Type.NUMBER },
              interpolation: { type: Type.STRING }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateFinalVisualization = async (char: CharacterParameters, mach: MachineParameters): Promise<string> => {
  const prompt = `A highly detailed, 3D render style image of a ${char.physique} person with ${char.body_type} wearing ${char.clothing_description} correctly seated on a ${mach.brand} ${mach.name} ${mach.exercise_type} machine. The character is performing the exercise in a professional gym environment. High quality, clear lighting, perfect anatomy.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: { aspectRatio: '16:9' }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

import React, { useState, useCallback } from 'react';
import { 
  Dumbbell, 
  User, 
  Settings, 
  Cpu, 
  FileJson, 
  Download, 
  Play, 
  Loader2, 
  ArrowRight,
  Upload,
  Sparkles,
  Info
} from 'lucide-react';
import * as gemini from './services/geminiService';
import { AnalysisState, CharacterParameters, MachineParameters, UnifiedMotionData } from './types';

export default function App() {
  const [charImage, setCharImage] = useState<string | null>(null);
  const [machImage, setMachImage] = useState<string | null>(null);
  const [machDetails, setMachDetails] = useState({ name: '', brand: '', exercise: '' });

  const [state, setState] = useState<AnalysisState>({
    character: null,
    machine: null,
    unified: null,
    generatedImageUrl: null,
    isAnalyzing: false,
    isGenerating: false,
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'char' | 'mach') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'char') setCharImage(reader.result as string);
        else setMachImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!charImage || !machImage) return;

    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const [charData, machData] = await Promise.all([
        gemini.analyzeCharacterImage(charImage),
        gemini.analyzeMachineImage(machImage, machDetails)
      ]);

      setState(prev => ({
        ...prev,
        character: charData,
        machine: machData,
        isAnalyzing: false
      }));
    } catch (error) {
      console.error("Analysis failed", error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
      alert("Error analyzing images. Please check your API key and try again.");
    }
  };

  const generateResult = async () => {
    if (!state.character || !state.machine) return;

    setState(prev => ({ ...prev, isGenerating: true }));
    try {
      const [unified, imgUrl] = await Promise.all([
        gemini.generateUnifiedMotion(state.character, state.machine),
        gemini.generateFinalVisualization(state.character, state.machine)
      ]);

      setState(prev => ({
        ...prev,
        unified,
        generatedImageUrl: imgUrl,
        isGenerating: false
      }));
    } catch (error) {
      console.error("Generation failed", error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Error generating output.");
    }
  };

  const downloadJson = () => {
    if (!state.unified) return;
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({
      character: state.character,
      machine: state.machine,
      motion: state.unified
    }, null, 2));
    const downloadAnchorNode = document.createElement('a');
    downloadAnchorNode.setAttribute("href", dataStr);
    downloadAnchorNode.setAttribute("download", "blender_motion_config.json");
    document.body.appendChild(downloadAnchorNode);
    downloadAnchorNode.click();
    downloadAnchorNode.remove();
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="py-8 px-6 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg shadow-lg shadow-indigo-500/20">
              <Dumbbell className="w-8 h-8 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                GymRig AI
              </h1>
              <p className="text-sm text-slate-400">Digital Twin Character-Machine Synchronizer</p>
            </div>
          </div>
          <div className="hidden md:flex items-center gap-4 text-sm font-medium text-slate-400">
            <div className="flex items-center gap-1.5"><Sparkles className="w-4 h-4" /> Analyze</div>
            <ArrowRight className="w-4 h-4 opacity-50" />
            <div className="flex items-center gap-1.5"><Cpu className="w-4 h-4" /> Synthesize</div>
            <ArrowRight className="w-4 h-4 opacity-50" />
            <div className="flex items-center gap-1.5"><Download className="w-4 h-4" /> Export</div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-12 space-y-12">
        {/* Step 1: Uploads */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {/* Character Upload */}
          <div className="glass-panel rounded-2xl p-6 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <User className="w-5 h-5 text-indigo-400" />
              <h2 className="font-semibold text-lg">Character Input</h2>
            </div>
            <div 
              className={`relative h-64 border-2 border-dashed rounded-xl flex flex-col items-center justify-center transition-all ${
                charImage ? 'border-indigo-500/50' : 'border-slate-700 hover:border-slate-500'
              } overflow-hidden group`}
            >
              {charImage ? (
                <>
                  <img src={charImage} className="w-full h-full object-cover" alt="Character" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <label className="cursor-pointer bg-white text-black px-4 py-2 rounded-lg font-medium">Change Image</label>
                  </div>
                </>
              ) : (
                <div className="text-center p-6">
                  <Upload className="w-10 h-10 text-slate-500 mx-auto mb-3" />
                  <p className="text-slate-400 font-medium">Upload Character Image</p>
                  <p className="text-xs text-slate-500 mt-1">Front or perspective view preferred</p>
                </div>
              )}
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileChange(e, 'char')} />
            </div>
          </div>

          {/* Machine Upload */}
          <div className="glass-panel rounded-2xl p-6 space-y-4">
            <div className="flex items-center gap-2 mb-2">
              <Settings className="w-5 h-5 text-emerald-400" />
              <h2 className="font-semibold text-lg">Gym Machine Input</h2>
            </div>
            <div 
              className={`relative h-64 border-2 border-dashed rounded-xl flex flex-col items-center justify-center transition-all ${
                machImage ? 'border-emerald-500/50' : 'border-slate-700 hover:border-slate-500'
              } overflow-hidden group`}
            >
              {machImage ? (
                <>
                  <img src={machImage} className="w-full h-full object-cover" alt="Machine" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
                    <label className="cursor-pointer bg-white text-black px-4 py-2 rounded-lg font-medium">Change Image</label>
                  </div>
                </>
              ) : (
                <div className="text-center p-6">
                  <Upload className="w-10 h-10 text-slate-500 mx-auto mb-3" />
                  <p className="text-slate-400 font-medium">Upload Machine Image</p>
                  <p className="text-xs text-slate-500 mt-1">Side profile for mechanics detection</p>
                </div>
              )}
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileChange(e, 'mach')} />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-2">
              <div>
                <label className="text-xs text-slate-500 font-medium uppercase tracking-wider mb-1 block">Machine Name</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-emerald-500"
                  placeholder="e.g. Leg Press"
                  value={machDetails.name}
                  onChange={(e) => setMachDetails(prev => ({...prev, name: e.target.value}))}
                />
              </div>
              <div>
                <label className="text-xs text-slate-500 font-medium uppercase tracking-wider mb-1 block">Brand</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-emerald-500"
                  placeholder="e.g. LifeFitness"
                  value={machDetails.brand}
                  onChange={(e) => setMachDetails(prev => ({...prev, brand: e.target.value}))}
                />
              </div>
              <div>
                <label className="text-xs text-slate-500 font-medium uppercase tracking-wider mb-1 block">Exercise</label>
                <input 
                  type="text" 
                  className="w-full bg-slate-900 border border-slate-700 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-1 focus:ring-emerald-500"
                  placeholder="e.g. Quadriceps"
                  value={machDetails.exercise}
                  onChange={(e) => setMachDetails(prev => ({...prev, exercise: e.target.value}))}
                />
              </div>
            </div>
          </div>
        </section>

        {/* Action Button: Analysis */}
        <div className="flex justify-center">
          <button 
            onClick={startAnalysis}
            disabled={state.isAnalyzing || !charImage || !machImage}
            className={`flex items-center gap-3 px-8 py-4 rounded-full font-bold text-lg transition-all shadow-xl shadow-indigo-600/20 ${
              state.isAnalyzing || !charImage || !machImage
                ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
                : 'bg-indigo-600 hover:bg-indigo-500 text-white scale-105 active:scale-95'
            }`}
          >
            {state.isAnalyzing ? (
              <Loader2 className="w-6 h-6 animate-spin" />
            ) : (
              <Sparkles className="w-6 h-6" />
            )}
            {state.isAnalyzing ? 'Extracting Parameters...' : 'Decompose & Analyze'}
          </button>
        </div>

        {/* Analysis Results */}
        {state.character && state.machine && (
          <section className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="glass-panel rounded-2xl overflow-hidden border-indigo-500/20">
              <div className="bg-indigo-500/10 px-6 py-4 flex items-center justify-between border-b border-indigo-500/20">
                <span className="font-bold flex items-center gap-2"><User className="w-4 h-4" /> Character Data (JSON)</span>
                <span className="text-[10px] bg-indigo-500 text-white px-2 py-0.5 rounded-full font-bold uppercase tracking-widest">Detected</span>
              </div>
              <pre className="p-6 text-sm font-mono text-indigo-300/80 max-h-64 overflow-y-auto custom-scrollbar">
                {JSON.stringify(state.character, null, 2)}
              </pre>
            </div>

            <div className="glass-panel rounded-2xl overflow-hidden border-emerald-500/20">
              <div className="bg-emerald-500/10 px-6 py-4 flex items-center justify-between border-b border-emerald-500/20">
                <span className="font-bold flex items-center gap-2"><Settings className="w-4 h-4" /> Machine Data (JSON)</span>
                <span className="text-[10px] bg-emerald-500 text-white px-2 py-0.5 rounded-full font-bold uppercase tracking-widest">Detected</span>
              </div>
              <pre className="p-6 text-sm font-mono text-emerald-300/80 max-h-64 overflow-y-auto custom-scrollbar">
                {JSON.stringify(state.machine, null, 2)}
              </pre>
            </div>
          </section>
        )}

        {/* Synthesis Phase */}
        {state.character && state.machine && (
          <div className="flex flex-col items-center gap-8 py-8">
            <div className="flex items-center gap-3 text-slate-400">
              <div className="h-px w-24 bg-slate-800" />
              <p className="text-sm font-medium uppercase tracking-widest">Synchronization Phase</p>
              <div className="h-px w-24 bg-slate-800" />
            </div>

            <button 
              onClick={generateResult}
              disabled={state.isGenerating}
              className={`flex items-center gap-3 px-10 py-5 rounded-full font-bold text-xl transition-all shadow-2xl ${
                state.isGenerating
                  ? 'bg-slate-800 text-slate-500 cursor-not-allowed'
                  : 'bg-gradient-to-r from-indigo-600 to-emerald-600 hover:from-indigo-500 hover:to-emerald-500 text-white scale-105 active:scale-95'
              }`}
            >
              {state.isGenerating ? (
                <Loader2 className="w-7 h-7 animate-spin" />
              ) : (
                <Cpu className="w-7 h-7" />
              )}
              {state.isGenerating ? 'Synthesizing Rig...' : 'Synchronize & Generate Simulation'}
            </button>
          </div>
        )}

        {/* Final Results & Visualization */}
        {state.unified && state.generatedImageUrl && (
          <section className="space-y-8 animate-in zoom-in-95 duration-700">
            <div className="grid grid-cols-1 lg:grid-cols-5 gap-8">
              {/* Generated Image */}
              <div className="lg:col-span-3 glass-panel rounded-3xl overflow-hidden relative shadow-2xl group border-white/5">
                <div className="absolute top-4 left-4 z-10">
                  <span className="bg-indigo-600 text-white px-3 py-1 rounded-full text-xs font-bold shadow-lg flex items-center gap-1.5">
                    <Play className="w-3 h-3 fill-white" /> Live Simulation Preview
                  </span>
                </div>
                <img src={state.generatedImageUrl} className="w-full aspect-video object-cover" alt="Simulated result" />
                <div className="p-6 bg-slate-900/80 backdrop-blur-sm border-t border-white/5 flex items-center justify-between">
                  <div>
                    <h3 className="text-xl font-bold">{state.unified.exercise_name}</h3>
                    <p className="text-slate-400 text-sm">Character-Machine interaction simulation generated</p>
                  </div>
                  <div className="flex gap-2">
                    <button 
                      onClick={downloadJson}
                      className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-sm font-semibold transition-colors"
                    >
                      <FileJson className="w-4 h-4" /> Export JSON
                    </button>
                    <button className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-4 py-2 rounded-xl text-sm font-semibold transition-colors shadow-lg shadow-indigo-500/20">
                      <Download className="w-4 h-4" /> Download Scene
                    </button>
                  </div>
                </div>
              </div>

              {/* Interaction Details */}
              <div className="lg:col-span-2 space-y-4">
                <div className="glass-panel p-6 rounded-3xl h-full flex flex-col">
                  <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                    <Info className="w-5 h-5 text-indigo-400" /> Interaction Logic
                  </h3>
                  <div className="space-y-6 flex-1">
                    <div className="p-4 bg-slate-800/50 rounded-2xl border border-white/5">
                      <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Key Contact Points</h4>
                      <ul className="space-y-3">
                        <li className="flex items-center justify-between text-sm">
                          <span className="text-slate-400">Hands</span>
                          <span className="font-mono text-indigo-400">{state.unified.interaction_points.hands}</span>
                        </li>
                        <li className="flex items-center justify-between text-sm">
                          <span className="text-slate-400">Feet</span>
                          <span className="font-mono text-indigo-400">{state.unified.interaction_points.feet}</span>
                        </li>
                        <li className="flex items-center justify-between text-sm">
                          <span className="text-slate-400">Back/Core</span>
                          <span className="font-mono text-indigo-400">{state.unified.interaction_points.back}</span>
                        </li>
                      </ul>
                    </div>

                    <div className="p-4 bg-slate-800/50 rounded-2xl border border-white/5">
                      <h4 className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-3">Blender Export Config</h4>
                      <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-1">
                          <p className="text-xs text-slate-500">Keyframes</p>
                          <p className="text-sm font-bold">{state.unified.blender_keyframe_data.frame_start} - {state.unified.blender_keyframe_data.frame_end}</p>
                        </div>
                        <div className="space-y-1">
                          <p className="text-xs text-slate-500">Interpolation</p>
                          <p className="text-sm font-bold capitalize">{state.unified.blender_keyframe_data.interpolation}</p>
                        </div>
                      </div>
                    </div>

                    <div className="flex-1 flex flex-col justify-end">
                      <div className="p-4 bg-indigo-900/30 border border-indigo-500/30 rounded-2xl">
                        <p className="text-xs text-indigo-200/80 leading-relaxed italic">
                          "Ready for Rigify import. This configuration maps the Character's detected skeleton directly to the {state.machine.brand} {state.machine.name} pivot constraints."
                        </p>
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </section>
        )}
      </main>

      {/* Persistent Call to Action (Fixed Footer if needed, but here simple info) */}
      <footer className="mt-20 border-t border-slate-800 py-10 px-6 text-center text-slate-500 text-sm">
        <p>© 2024 GymRig AI • Advanced 3D Character Pipeline</p>
        <p className="mt-2 text-slate-600">Built with Gemini 3 for precise mechanical analysis</p>
      </footer>
    </div>
  );
}

export interface CharacterParameters {
  physique: string;
  height_estimate_cm: number;
  body_type: string;
  clothing_description: string;
  major_joints_detected: string[];
  rig_complexity: 'low' | 'medium' | 'high';
}

export interface MachineParameters {
  name: string;
  brand: string;
  exercise_type: string;
  mechanical_pivots: string[];
  seat_height_ratio: number;
  handle_type: string;
  resistance_type: string;
}

export interface UnifiedMotionData {
  exercise_name: string;
  character_offset: { x: number; y: number; z: number };
  binding_points: {
    hands_to_handles: string;
    feet_to_pedals: string;
    hips_to_seat: string;
    chest_to_pad?: string;
  };
  animation_cycle: {
    start_pose: string;
