export const generateFinalVisualization = async (char: CharacterParameters, mach: MachineParameters): Promise<string> => {
  const prompt = `A cinematic 3D render of a ${char.physique} character with ${char.body_type} body type, wearing ${char.clothing_description}, MOUNTED AND SEATED CORRECTLY on a ${mach.brand} ${mach.name} ${mach.exercise_type} machine. The character's hands are gripping the handles, and their feet are on the pads. Action shot showing the character in the middle of a heavy repetition. Hyper-realistic, professional gym lighting, 8k resolution, Blender Cycles style render.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: { aspectRatio: '16:9' }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

import React, { useState } from 'react';
import { 
  Dumbbell, 
  User, 
  Settings, 
  Cpu, 
  FileJson, 
  Download, 
  Play, 
  Loader2, 
  ArrowRight,
  Upload,
  Sparkles,
  Info,
  Link as LinkIcon,
  Layers
} from 'lucide-react';
import * as gemini from './services/geminiService';
import { AnalysisState } from './types';

export default function App() {
  const [charImage, setCharImage] = useState<string | null>(null);
  const [machImage, setMachImage] = useState<string | null>(null);
  const [machDetails, setMachDetails] = useState({ name: '', brand: '', exercise: '' });

  const [state, setState] = useState<AnalysisState>({
    character: null,
    machine: null,
    unified: null,
    generatedImageUrl: null,
    isAnalyzing: false,
    isGenerating: false,
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'char' | 'mach') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'char') setCharImage(reader.result as string);
        else setMachImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!charImage || !machImage) return;
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const [charData, machData] = await Promise.all([
        gemini.analyzeCharacterImage(charImage),
        gemini.analyzeMachineImage(machImage, machDetails)
      ]);
      setState(prev => ({ ...prev, character: charData, machine: machData, isAnalyzing: false }));
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
      alert("Analysis failed.");
    }
  };

  const generateResult = async () => {
    if (!state.character || !state.machine) return;
    setState(prev => ({ ...prev, isGenerating: true }));
    try {
      const [unified, imgUrl] = await Promise.all([
        gemini.generateUnifiedMotion(state.character, state.machine),
        gemini.generateFinalVisualization(state.character, state.machine)
      ]);
      setState(prev => ({ ...prev, unified, generatedImageUrl: imgUrl, isGenerating: false }));
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Synthesis failed.");
    }
  };

  const downloadFullProject = () => {
    if (!state.unified) return;
    const fullData = {
      character: state.character,
      machine: state.machine,
      interaction_rig: state.unified
    };
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(fullData, null, 2));
    const dlAnchor = document.createElement('a');
    dlAnchor.setAttribute("href", dataStr);
    dlAnchor.setAttribute("download", `gymrig_fusion_${state.unified.exercise_name.replace(/\s+/g, '_')}.json`);
    document.body.appendChild(dlAnchor);
    dlAnchor.click();
    dlAnchor.remove();
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="py-8 px-6 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg shadow-lg">
              <Dumbbell className="w-8 h-8 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">GymRig AI Fusion</h1>
              <p className="text-sm text-slate-400 italic">Advanced Character-Machine Synchronization</p>
            </div>
          </div>
          <div className="hidden md:flex items-center gap-6">
             <div className="flex flex-col items-end">
                <span className="text-xs text-slate-500 uppercase font-bold tracking-tighter">Export Target</span>
                <span className="text-sm text-indigo-400 font-mono">Blender 4.2+ / Rigify</span>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-12 space-y-12">
        {/* Step 1: Image Inputs */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="glass-panel rounded-2xl p-6 border-indigo-500/20">
            <h2 className="font-bold text-lg mb-4 flex items-center gap-2"><User className="w-5 h-5 text-indigo-400" /> 1. Character Analysis</h2>
            <div className="relative h-64 border-2 border-dashed border-slate-700 rounded-xl overflow-hidden group">
              {charImage ? <img src={charImage} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center justify-center h-full text-slate-500"><Upload className="mb-2" /> Upload Subject</div>}
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileChange(e, 'char')} />
            </div>
          </div>

          <div className="glass-panel rounded-2xl p-6 border-emerald-500/20">
            <h2 className="font-bold text-lg mb-4 flex items-center gap-2"><Settings className="w-5 h-5 text-emerald-400" /> 2. Machine Analysis</h2>
            <div className="relative h-64 border-2 border-dashed border-slate-700 rounded-xl overflow-hidden group">
              {machImage ? <img src={machImage} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center justify-center h-full text-slate-500"><Upload className="mb-2" /> Upload Equipment</div>}
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileChange(e, 'mach')} />
            </div>
            <div className="grid grid-cols-3 gap-3 mt-4">
              <input type="text" placeholder="Machine Name" className="bg-slate-900 border border-slate-700 rounded px-2 py-1.5 text-xs focus:ring-1 focus:ring-emerald-500 outline-none" value={machDetails.name} onChange={e => setMachDetails(p => ({...p, name: e.target.value}))} />
              <input type="text" placeholder="Brand" className="bg-slate-900 border border-slate-700 rounded px-2 py-1.5 text-xs focus:ring-1 focus:ring-emerald-500 outline-none" value={machDetails.brand} onChange={e => setMachDetails(p => ({...p, brand: e.target.value}))} />
              <input type="text" placeholder="Exercise" className="bg-slate-900 border border-slate-700 rounded px-2 py-1.5 text-xs focus:ring-1 focus:ring-emerald-500 outline-none" value={machDetails.exercise} onChange={e => setMachDetails(p => ({...p, exercise: e.target.value}))} />
            </div>
          </div>
        </section>

        {/* Analyze Buttons */}
        <div className="flex justify-center">
          <button 
            onClick={startAnalysis} 
            disabled={state.isAnalyzing || !charImage || !machImage}
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 px-8 py-3 rounded-full font-bold transition-all disabled:opacity-50"
          >
            {state.isAnalyzing ? <Loader2 className="animate-spin" /> : <Sparkles />} 
            Decompose Parameters (JSON)
          </button>
        </div>

        {/* Parameter FUSION Section */}
        {state.character && state.machine && (
          <section className="space-y-8 animate-in fade-in duration-500">
            <div className="flex items-center gap-4 py-4">
              <div className="h-px flex-1 bg-gradient-to-r from-transparent to-slate-800" />
              <Layers className="text-slate-500" />
              <h2 className="text-xl font-bold uppercase tracking-widest text-slate-400">Parameter Fusion Engine</h2>
              <div className="h-px flex-1 bg-gradient-to-l from-transparent to-slate-800" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               <div className="glass-panel rounded-xl p-4 bg-indigo-500/5">
                  <p className="text-[10px] text-indigo-400 font-bold uppercase mb-2">Character Node</p>
                  <pre className="text-[11px] font-mono text-indigo-200/60 h-32 overflow-auto">{JSON.stringify(state.character, null, 2)}</pre>
               </div>
               <div className="glass-panel rounded-xl p-4 bg-emerald-500/5">
                  <p className="text-[10px] text-emerald-400 font-bold uppercase mb-2">Machine Node</p>
                  <pre className="text-[11px] font-mono text-emerald-200/60 h-32 overflow-auto">{JSON.stringify(state.machine, null, 2)}</pre>
               </div>
            </div>

            <div className="flex justify-center flex-col items-center gap-4">
               <button 
                onClick={generateResult} 
                disabled={state.isGenerating}
                className="flex items-center gap-3 bg-gradient-to-r from-indigo-600 to-emerald-600 hover:brightness-110 px-10 py-4 rounded-full font-black text-lg transition-transform active:scale-95 disabled:opacity-50 shadow-2xl shadow-indigo-500/20"
              >
                {state.isGenerating ? <Loader2 className="animate-spin" /> : <LinkIcon />}
                Fuse & Mount Character on Machine
              </button>
              <p className="text-xs text-slate-500 flex items-center gap-1.5"><Info className="w-3 h-3" /> This step joins both skeletons into a single motion context</p>
            </div>
          </section>
        )}

        {/* Final Integrated Result */}
        {state.unified && state.generatedImageUrl && (
          <section className="space-y-6 animate-in zoom-in-95 duration-700">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              {/* Visual Result */}
              <div className="lg:col-span-2 glass-panel rounded-3xl overflow-hidden border-white/10 shadow-2xl relative group">
                <img src={state.generatedImageUrl} className="w-full aspect-video object-cover group-hover:scale-105 transition-transform duration-1000" />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent pointer-events-none" />
                <div className="absolute bottom-6 left-6 right-6">
                  <h3 className="text-2xl font-black text-white">{state.unified.exercise_name}</h3>
                  <p className="text-slate-300 text-sm">Character fully integrated with machine rig constraints</p>
                </div>
              </div>

              {/* Fused JSON Data */}
              <div className="glass-panel rounded-3xl p-6 border-white/5 flex flex-col">
                <div className="flex items-center justify-between mb-4">
                  <h4 className="font-bold flex items-center gap-2"><FileJson className="w-4 h-4 text-emerald-400" /> Fused Project JSON</h4>
                  <button onClick={downloadFullProject} className="p-2 hover:bg-white/10 rounded-lg transition-colors text-indigo-400"><Download className="w-5 h-5" /></button>
                </div>
                <div className="flex-1 overflow-hidden flex flex-col gap-4">
                   <div className="bg-slate-900/80 p-4 rounded-xl border border-white/5 flex-1 overflow-auto custom-scrollbar">
                      <p className="text-[10px] text-slate-500 font-bold uppercase mb-2">Binding Logic (IK Constraints)</p>
                      <pre className="text-[11px] font-mono text-emerald-400/80">{JSON.stringify(state.unified.binding_points, null, 2)}</pre>
                      <div className="h-px w-full bg-white/5 my-4" />
                      <p className="text-[10px] text-slate-500 font-bold uppercase mb-2">3D Transformation Matrix</p>
                      <pre className="text-[11px] font-mono text-indigo-400/80">{JSON.stringify(state.unified.character_offset, null, 2)}</pre>
                      <div className="h-px w-full bg-white/5 my-4" />
                      <p className="text-[10px] text-slate-500 font-bold uppercase mb-2">Animation Cycle Poses</p>
                      <pre className="text-[11px] font-mono text-slate-300">{JSON.stringify(state.unified.animation_cycle, null, 2)}</pre>
                   </div>
                   <button 
                    onClick={downloadFullProject}
                    className="w-full bg-white text-black font-bold py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-slate-200 transition-colors"
                   >
                     <FileJson className="w-4 h-4" /> Export Combined JSON for Blender
                   </button>
                </div>
              </div>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

