          },
          movement_logic: {
            type: Type.OBJECT,
            properties: {
              concentric_phase: { type: Type.STRING },
              eccentric_phase: { type: Type.STRING },
              posture_requirements: { type: Type.STRING },
              efficiency_tips: { type: Type.STRING }
            },
            required: ['concentric_phase', 'eccentric_phase', 'posture_requirements', 'efficiency_tips']
          },
          animation_cycle: {
            type: Type.OBJECT,
            properties: {
              start_pose: { type: Type.STRING },
              peak_contraction: { type: Type.STRING },
              return_pose: { type: Type.STRING }
            }
          },
          ik_targets: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                target_bone: { type: Type.STRING },
                influence: { type: Type.NUMBER }
              }
            }
          },
          blender_keyframe_data: {
            type: Type.OBJECT,
            properties: {
              frame_start: { type: Type.NUMBER },
              frame_end: { type: Type.NUMBER },
              interpolation: { type: Type.STRING },
              framerate: { type: Type.NUMBER }
            }
          }
        },
        required: ['exercise_name', 'character_offset', 'binding_points', 'movement_logic', 'animation_cycle', 'ik_targets', 'blender_keyframe_data']
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateFinalVisualization = async (char: CharacterParameters, mach: MachineParameters): Promise<string> => {
  const prompt = `A cinematic 3D render of a ${char.physique} character with ${char.body_type} body type, wearing ${char.clothing_description}, MOUNTED AND SEATED CORRECTLY on a ${mach.brand} ${mach.name} ${mach.exercise_type} machine. The character's hands are gripping the handles, and their feet are on the pads. Action shot showing the character in the middle of a heavy repetition. Hyper-realistic, professional gym lighting, 8k resolution, Blender Cycles style render.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: { aspectRatio: '16:9' }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

import React, { useState } from 'react';
