import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CharacterParameters, MachineParameters, UnifiedMotionData, GroundingSource } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCharacterImage = async (base64Image: string): Promise<CharacterParameters> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: 'Analyze this character for 3D rigging. Extract physique details, estimated height, body type, clothing, and detectable joints. Return as JSON.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          physique: { type: Type.STRING },
          height_estimate_cm: { type: Type.NUMBER },
          body_type: { type: Type.STRING },
          clothing_description: { type: Type.STRING },
          major_joints_detected: { type: Type.ARRAY, items: { type: Type.STRING } },
          rig_complexity: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['physique', 'height_estimate_cm', 'body_type', 'clothing_description', 'major_joints_detected', 'rig_complexity']
      }
    }
  });

  return JSON.parse(response.text);
};

export const analyzeMachineImage = async (
  base64Image: string, 
  details?: { name?: string, brand?: string, exercise?: string }
): Promise<{ data: MachineParameters, sources: GroundingSource[] }> => {
  const prompt = `Deeply decompose this gym equipment for mechanical simulation. 
  Details provided: Name: ${details?.name || 'unknown'}, Brand: ${details?.brand || 'unknown'}, Exercise: ${details?.exercise || 'unknown'}. 

  MANDATORY: Use Google Search to find the exact manual or professional usage guide for this machine (or the closest equivalent by brand: ${details?.brand}). 
  Identify: 
  1. Real-world mechanical behavior (specific movement arc or linear path).
  2. Professional range of motion limits.
  3. Safety pivot points.
  4. Ergonomic usage instructions for maximum efficiency.
  5. Primary muscle groups targeted.

  Return the result in JSON format matching the requested schema.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          exercise_type: { type: Type.STRING },
          mechanical_pivots: { type: Type.ARRAY, items: { type: Type.STRING } },
          seat_height_ratio: { type: Type.NUMBER },
          handle_type: { type: Type.STRING },
          resistance_type: { type: Type.STRING },
          mechanical_behavior: {
            type: Type.OBJECT,
            properties: {
              movement_axis: { type: Type.STRING, enum: ['linear', 'arc', 'multiaxial'] },
              range_of_motion_degrees: { type: Type.NUMBER },
              travel_distance_cm: { type: Type.NUMBER },
              safety_limit_points: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['movement_axis', 'safety_limit_points']
          },
          usage_instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
          primary_muscle_groups: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['name', 'brand', 'exercise_type', 'mechanical_pivots', 'seat_height_ratio', 'handle_type', 'resistance_type', 'mechanical_behavior', 'usage_instructions', 'primary_muscle_groups']
      }
    }
  });

  const sources: GroundingSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({ title: chunk.web.title, uri: chunk.web.uri });
      }
    });
  }

  return { 
    data: JSON.parse(response.text), 
    sources 
  };
};

