  Activity,
  ClipboardList,
  Search,
  ExternalLink,
  Globe
} from 'lucide-react';
import * as gemini from './services/geminiService';
import { AnalysisState } from './types';

export default function App() {
  const [charImage, setCharImage] = useState<string | null>(null);
  const [machImage, setMachImage] = useState<string | null>(null);
  const [machDetails, setMachDetails] = useState({ name: '', brand: '', exercise: '' });

  const [state, setState] = useState<AnalysisState>({
    character: null,
    machine: null,
    unified: null,
    groundingSources: [],
    generatedImageUrl: null,
    isAnalyzing: false,
    isGenerating: false,
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'char' | 'mach') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'char') setCharImage(reader.result as string);
        else setMachImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!charImage || !machImage) return;
    setState(prev => ({ ...prev, isAnalyzing: true, groundingSources: [] }));
    try {
      const charData = await gemini.analyzeCharacterImage(charImage);
      const machResult = await gemini.analyzeMachineImage(machImage, machDetails);

      setState(prev => ({ 
        ...prev, 
        character: charData, 
        machine: machResult.data, 
        groundingSources: machResult.sources,
        isAnalyzing: false 
      }));
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
      alert("Analysis failed. Please check your API key.");
    }
  };

  const generateResult = async () => {
    if (!state.character || !state.machine) return;
    setState(prev => ({ ...prev, isGenerating: true }));
    try {
      const [unified, imgUrl] = await Promise.all([
        gemini.generateUnifiedMotion(state.character, state.machine),
        gemini.generateFinalVisualization(state.character, state.machine)
      ]);
      setState(prev => ({ ...prev, unified, generatedImageUrl: imgUrl, isGenerating: false }));
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Synthesis failed.");
    }
  };

  const downloadFullProject = () => {
    if (!state.unified) return;
    const fullData = {
      character: state.character,
      machine: state.machine,
      research_sources: state.groundingSources,
      interaction_rig: state.unified
