import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { CharacterParameters, MachineParameters, UnifiedMotionData, GroundingSource } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCharacterImage = async (base64Image: string): Promise<CharacterParameters> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: 'Analyze this character for 3D rigging. Extract physique details, estimated height, body type, clothing, and detectable joints. Return as JSON.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          physique: { type: Type.STRING },
          height_estimate_cm: { type: Type.NUMBER },
          body_type: { type: Type.STRING },
          clothing_description: { type: Type.STRING },
          major_joints_detected: { type: Type.ARRAY, items: { type: Type.STRING } },
          rig_complexity: { type: Type.STRING, enum: ['low', 'medium', 'high'] }
        },
        required: ['physique', 'height_estimate_cm', 'body_type', 'clothing_description', 'major_joints_detected', 'rig_complexity']
      }
    }
  });

  return JSON.parse(response.text);
};

export const analyzeMachineImage = async (
  base64Image: string, 
  details?: { name?: string, brand?: string, exercise?: string }
): Promise<{ data: MachineParameters, sources: GroundingSource[] }> => {
  const prompt = `Act as a Biomechanical Synchronization Expert. Analyze this gym equipment for a precise 3D simulation. 
  Machine info: ${details?.name || 'Inferred from image'}, Brand: ${details?.brand || 'Inferred'}, Target Exercise: ${details?.exercise || 'Inferred'}. 

  MANDATORY: Search for professional biomechanical studies or technical manuals for this specific equipment. 
  Identify: 
  1. Mechanical movement path (arc, linear, or complex).
  2. Safety limits for joints (e.g., knee lockout warnings).
  3. Pivot points relative to a standard human skeleton.
  4. Exact muscle groups targeted for the specified exercise.

  Return the result in JSON format.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          exercise_type: { type: Type.STRING },
          mechanical_pivots: { type: Type.ARRAY, items: { type: Type.STRING } },
          seat_height_ratio: { type: Type.NUMBER },
          handle_type: { type: Type.STRING },
          resistance_type: { type: Type.STRING },
          mechanical_behavior: {
            type: Type.OBJECT,
            properties: {
              movement_axis: { type: Type.STRING, enum: ['linear', 'arc', 'multiaxial'] },
              range_of_motion_degrees: { type: Type.NUMBER },
              travel_distance_cm: { type: Type.NUMBER },
              safety_limit_points: { type: Type.ARRAY, items: { type: Type.STRING } }
            },
            required: ['movement_axis', 'safety_limit_points']
          },
          usage_instructions: { type: Type.ARRAY, items: { type: Type.STRING } },
          primary_muscle_groups: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['name', 'brand', 'exercise_type', 'mechanical_pivots', 'seat_height_ratio', 'handle_type', 'resistance_type', 'mechanical_behavior', 'usage_instructions', 'primary_muscle_groups']
      }
    }
  });

  const sources: GroundingSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) {
        sources.push({ title: chunk.web.title, uri: chunk.web.uri });
      }
    });
  }

  return { 
    data: JSON.parse(response.text), 
    sources 
  };
};

export const generateUnifiedMotion = async (char: CharacterParameters, mach: MachineParameters, exerciseName: string): Promise<UnifiedMotionData> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `SYSTEM ROLE: Biomechanical Synchronization System for 3D Environments.
    CONTEXT: Fusing a character with a gym machine for the exercise: "${exerciseName || mach.exercise_type}".

    Character Specs: ${JSON.stringify(char)}. 
    Machine Specs: ${JSON.stringify(mach)}. 

    TASK: Generate a high-precision biomechanical fusion. 
    1. Align character joints (especially ${char.major_joints_detected.join(', ')}) with machine pivot points.
    2. Prioritize joint safety (prevent overextension or dangerous torque).
    3. Calculate 3D offsets to mount the character correctly.
    4. Provide ergonomic corrections to ensure perfect form.

    Return result as JSON for Blender/Rigify export.`,
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          exercise_name: { type: Type.STRING },
          biomechanical_assessment: {
            type: Type.OBJECT,
            properties: {
              ergonomic_alignment_score: { type: Type.NUMBER },
              joint_safety_warnings: { type: Type.ARRAY, items: { type: Type.STRING } },
              posture_corrections: { type: Type.STRING }
            }
          },
          character_offset: {
            type: Type.OBJECT,
            properties: {
              x: { type: Type.NUMBER }, y: { type: Type.NUMBER }, z: { type: Type.NUMBER }
            }
          },
          binding_points: {
            type: Type.OBJECT,
            properties: {
              hands_to_handles: { type: Type.STRING },
              feet_to_pedals: { type: Type.STRING },
              hips_to_seat: { type: Type.STRING },
              chest_to_pad: { type: Type.STRING }
            }
          },
          movement_logic: {
            type: Type.OBJECT,
            properties: {
              concentric_phase: { type: Type.STRING },
              eccentric_phase: { type: Type.STRING },
              posture_requirements: { type: Type.STRING },
              efficiency_tips: { type: Type.STRING }
            }
          },
          animation_cycle: {
            type: Type.OBJECT,
            properties: {
              start_pose: { type: Type.STRING },
              peak_contraction: { type: Type.STRING },
              return_pose: { type: Type.STRING }
            }
          },
          ik_targets: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                target_bone: { type: Type.STRING },
                influence: { type: Type.NUMBER }
              }
            }
          },
          blender_keyframe_data: {
            type: Type.OBJECT,
            properties: {
              frame_start: { type: Type.NUMBER },
              frame_end: { type: Type.NUMBER },
              interpolation: { type: Type.STRING },
              framerate: { type: Type.NUMBER }
            }
          }
        },
        required: ['exercise_name', 'biomechanical_assessment', 'character_offset', 'binding_points', 'movement_logic', 'animation_cycle', 'ik_targets', 'blender_keyframe_data']
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateFinalVisualization = async (char: CharacterParameters, mach: MachineParameters, exercise: string): Promise<string> => {
  const prompt = `A highly professional biomechanical 3D simulation render of a ${char.physique} person (${char.body_type}) performing a ${exercise || mach.exercise_type} on a ${mach.brand} ${mach.name}. Focus on perfect posture and ergonomic alignment. The character's skeleton is perfectly synced with the machine's pivot points. Ultra-detailed, 8k, scientific visualization style.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: { aspectRatio: '16:9' }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }
  throw new Error("No image generated");
};

import React, { useState } from 'react';
import { 
  Dumbbell, 
  User, 
  Settings, 
  Cpu, 
  FileJson, 
  Download, 
  Play, 
  Loader2, 
  ArrowRight,
  Upload,
  Sparkles,
  Info,
  Link as LinkIcon,
  Layers,
  Activity,
  ClipboardList,
  Search,
  ExternalLink,
  Globe,
  ShieldAlert,
  ShieldCheck,
  Zap
} from 'lucide-react';
import * as gemini from './services/geminiService';
import { AnalysisState } from './types';

export default function App() {
  const [charImage, setCharImage] = useState<string | null>(null);
  const [machImage, setMachImage] = useState<string | null>(null);
  const [machDetails, setMachDetails] = useState({ name: '', brand: '', exercise: '' });

  const [state, setState] = useState<AnalysisState>({
    character: null,
    machine: null,
    unified: null,
    groundingSources: [],
    generatedImageUrl: null,
    isAnalyzing: false,
    isGenerating: false,
  });

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>, type: 'char' | 'mach') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'char') setCharImage(reader.result as string);
        else setMachImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const startAnalysis = async () => {
    if (!charImage || !machImage) return;
    setState(prev => ({ ...prev, isAnalyzing: true, groundingSources: [] }));
    try {
      const charData = await gemini.analyzeCharacterImage(charImage);
      const machResult = await gemini.analyzeMachineImage(machImage, machDetails);

      setState(prev => ({ 
        ...prev, 
        character: charData, 
        machine: machResult.data, 
        groundingSources: machResult.sources,
        isAnalyzing: false 
      }));
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
      alert("Analysis failed.");
    }
  };

  const generateResult = async () => {
    if (!state.character || !state.machine) return;
    setState(prev => ({ ...prev, isGenerating: true }));
    try {
      const [unified, imgUrl] = await Promise.all([
        gemini.generateUnifiedMotion(state.character, state.machine, machDetails.exercise),
        gemini.generateFinalVisualization(state.character, state.machine, machDetails.exercise)
      ]);
      setState(prev => ({ ...prev, unified, generatedImageUrl: imgUrl, isGenerating: false }));
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isGenerating: false }));
      alert("Synchronization failed.");
    }
  };

  const downloadFullProject = () => {
    if (!state.unified) return;
    const fullData = {
      system_meta: "Biomechanical Synchronization Output",
      character: state.character,
      machine: state.machine,
      interaction_rig: state.unified
    };
    const dataStr = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(fullData, null, 2));
    const dlAnchor = document.createElement('a');
    dlAnchor.setAttribute("href", dataStr);
    dlAnchor.setAttribute("download", `biomech_sync_${state.unified.exercise_name.replace(/\s+/g, '_')}.json`);
    document.body.appendChild(dlAnchor);
    dlAnchor.click();
    dlAnchor.remove();
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="py-8 px-6 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-indigo-600 rounded-lg shadow-lg">
              <Zap className="w-8 h-8 text-white" />
            </div>
            <div>
              <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400 italic">BiomechSync 3D</h1>
              <p className="text-sm text-slate-400 font-medium">Advanced Articular Safety & Rigging Fusion</p>
            </div>
          </div>
          <div className="hidden md:flex items-center gap-6">
             <div className="bg-emerald-500/10 border border-emerald-500/20 px-3 py-1 rounded-full flex items-center gap-2">
                <ShieldCheck className="w-4 h-4 text-emerald-400" />
                <span className="text-xs text-emerald-400 font-bold uppercase tracking-widest">Safety Mode Active</span>
             </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 mt-12 space-y-12">
        {/* Step 1: Inputs */}
        <section className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="glass-panel rounded-2xl p-6 border-indigo-500/20">
            <h2 className="font-bold text-lg mb-4 flex items-center gap-2"><User className="w-5 h-5 text-indigo-400" /> 1. Subject Input</h2>
            <div className="relative h-64 border-2 border-dashed border-slate-700 rounded-xl overflow-hidden group">
              {charImage ? <img src={charImage} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center justify-center h-full text-slate-500"><Upload className="mb-2" /> Select Character Image</div>}
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileChange(e, 'char')} />
            </div>
          </div>

          <div className="glass-panel rounded-2xl p-6 border-emerald-500/20">
            <h2 className="font-bold text-lg mb-4 flex items-center gap-2"><Settings className="w-5 h-5 text-emerald-400" /> 2. Machine Input</h2>
            <div className="relative h-64 border-2 border-dashed border-slate-700 rounded-xl overflow-hidden group">
              {machImage ? <img src={machImage} className="w-full h-full object-cover" /> : <div className="flex flex-col items-center justify-center h-full text-slate-500"><Upload className="mb-2" /> Select Machine Image</div>}
              <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => handleFileChange(e, 'mach')} />
            </div>
            <div className="space-y-3 mt-4">
              <input type="text" placeholder="Specific Exercise (e.g. Prone Leg Curl)" className="w-full bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none" value={machDetails.exercise} onChange={e => setMachDetails(p => ({...p, exercise: e.target.value}))} />
              <div className="grid grid-cols-2 gap-3">
                <input type="text" placeholder="Machine Name" className="bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none" value={machDetails.name} onChange={e => setMachDetails(p => ({...p, name: e.target.value}))} />
                <input type="text" placeholder="Brand (Optional)" className="bg-slate-900 border border-slate-700 rounded px-3 py-2 text-sm focus:ring-1 focus:ring-emerald-500 outline-none" value={machDetails.brand} onChange={e => setMachDetails(p => ({...p, brand: e.target.value}))} />
              </div>
            </div>
          </div>
        </section>

        {/* Analyze Buttons */}
        <div className="flex justify-center flex-col items-center gap-4">
          <button 
            onClick={startAnalysis} 
            disabled={state.isAnalyzing || !charImage || !machImage}
            className={`flex items-center gap-3 px-12 py-4 rounded-full font-black text-xl transition-all shadow-xl hover:scale-105 active:scale-95 ${
              state.isAnalyzing 
                ? 'bg-slate-800 text-slate-500' 
                : 'bg-indigo-600 hover:bg-indigo-500 text-white shadow-indigo-600/30'
            }`}
          >
            {state.isAnalyzing ? <Loader2 className="animate-spin w-6 h-6" /> : <Search className="w-6 h-6" />} 
            {state.isAnalyzing ? 'Analyzing Biomechanics...' : 'Run Biomechanical Analysis'}
          </button>
        </div>

        {/* Research Sources */}
        {state.groundingSources.length > 0 && (
          <div className="glass-panel rounded-2xl p-4 flex items-center gap-4 border-indigo-500/20">
             <Globe className="w-5 h-5 text-indigo-400" />
             <div className="flex-1 overflow-x-auto flex gap-6 text-xs text-indigo-300">
               {state.groundingSources.map((s, i) => (
                 <a key={i} href={s.uri} target="_blank" className="flex items-center gap-1 hover:underline"><ExternalLink className="w-3 h-3" /> {s.title}</a>
               ))}
             </div>
          </div>
        )}

        {/* Synthesis Phase */}
        {state.character && state.machine && (
          <section className="space-y-12">
            <div className="flex items-center gap-4">
              <div className="h-px flex-1 bg-slate-800" />
              <h2 className="text-xl font-black uppercase tracking-widest text-slate-500">Synchronization Engine</h2>
              <div className="h-px flex-1 bg-slate-800" />
            </div>

            <div className="flex justify-center">
              <button 
                onClick={generateResult} 
                disabled={state.isGenerating}
                className={`flex items-center gap-3 px-12 py-5 rounded-full font-black text-2xl transition-all shadow-2xl hover:scale-105 active:scale-95 ${
                  state.isGenerating 
                    ? 'bg-slate-800 text-slate-600' 
                    : 'bg-gradient-to-r from-indigo-600 via-purple-600 to-emerald-600 text-white'
                }`}
              >
                {state.isGenerating ? <Loader2 className="animate-spin w-8 h-8" /> : <LinkIcon className="w-8 h-8" />}
                Sync Skeleton & Fuse Rig
              </button>
            </div>
          </section>
        )}

        {/* Final Results */}
        {state.unified && state.generatedImageUrl && (
          <section className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-in zoom-in-95 duration-1000">
            {/* Visual Result */}
            <div className="lg:col-span-2 glass-panel rounded-3xl overflow-hidden shadow-2xl relative">
              <img src={state.generatedImageUrl} className="w-full aspect-video object-cover" />
              <div className="absolute top-6 left-6 flex gap-3">
                <div className="bg-black/60 backdrop-blur-md px-3 py-1.5 rounded-xl flex items-center gap-2 text-xs font-bold text-white border border-white/10">
                   <ShieldCheck className="w-4 h-4 text-emerald-400" /> 
                   Score: {state.unified.biomechanical_assessment.ergonomic_alignment_score}/100
                </div>
              </div>
              <div className="p-8 bg-slate-900/90 backdrop-blur-md border-t border-white/5">
                <h3 className="text-2xl font-black mb-1">{state.unified.exercise_name}</h3>
                <p className="text-slate-400 text-sm">Synchronized Biomechanical Simulation Data</p>
              </div>
            </div>

            {/* Rig Config & Safety */}
            <div className="space-y-6">
              <div className="glass-panel rounded-3xl p-6 border-red-500/20 bg-red-500/5">
                <h4 className="font-bold flex items-center gap-2 text-red-400 mb-4"><ShieldAlert className="w-5 h-5" /> Safety Warnings</h4>
                <ul className="text-xs space-y-3 text-red-200/80">
                  {state.unified.biomechanical_assessment.joint_safety_warnings.map((w, i) => (
                    <li key={i} className="flex gap-2"><span>•</span> {w}</li>
