              <div className="glass-panel rounded-3xl p-6 bg-slate-900/50 flex flex-col gap-6">
                 <div>
                   <p className="text-[10px] text-slate-500 font-black uppercase mb-3 tracking-tighter">Ergonomic Correction</p>
