import { GoogleGenAI, Type } from "@google/genai";
import { CharacterParameters, MachineParameters, BiomechSyncData, GroundingSource } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeCharacterImage = async (base64Image: string): Promise<CharacterParameters> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: 'Actúa como un experto en rigging 3D. Analiza este sujeto y extrae: físico, altura estimada, tipo de cuerpo, ropa y articulaciones detectables. Retorna JSON.' }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          physique: { type: Type.STRING },
          height_estimate_cm: { type: Type.NUMBER },
          body_type: { type: Type.STRING },
          clothing_description: { type: Type.STRING },
          major_joints_detected: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['physique', 'height_estimate_cm', 'body_type', 'clothing_description', 'major_joints_detected']
      }
    }
  });
  return JSON.parse(response.text);
};

export const analyzeMachineImage = async (base64Image: string): Promise<{ data: MachineParameters, sources: GroundingSource[] }> => {
  const prompt = `Actúa como un Sistema de Sincronización Biomecánica. Identifica esta máquina de gimnasio. 
  Usa Google Search para encontrar el nombre exacto del modelo, marca y su comportamiento mecánico real (ejes de rotación, poleas). 
  Retorna el nombre, marca, comportamiento y características detectadas en JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image.split(',')[1], mimeType: 'image/jpeg' } },
        { text: prompt }
      ]
    },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          brand: { type: Type.STRING },
          mechanical_behavior: { type: Type.STRING },
          detected_features: { type: Type.ARRAY, items: { type: Type.STRING } }
        },
        required: ['name', 'brand', 'mechanical_behavior', 'detected_features']
      }
    }
  });

  const sources: GroundingSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
    });
  }

  return { data: JSON.parse(response.text), sources };
};

export const syncBiomechanics = async (
  char: CharacterParameters, 
  mach: MachineParameters, 
  exercise: string
): Promise<BiomechSyncData> => {
  const prompt = `Actúa como un sistema de sincronización biomecánica para entornos 3D. 
