            }
          }
        },
        required: ['verificacion_grounding', 'analisis_sujeto_maquina', 'logica_movimiento', 'output_rig_blender']
      }
    }
  });

  return JSON.parse(response.text);
};

export const generateBiomechVisual = async (sync: BiomechSyncData, char: CharacterParameters): Promise<string> => {
  const prompt = `A professional 3D biomechanical visualization of a ${char.physique} character performing ${sync.verificacion_grounding.ejercicio_solicitado} on a ${sync.verificacion_grounding.maquina_identificada}. Scientific laboratory lighting, high-tech HUD elements in the background, showing bone structure and machine pivot alignment. Hyper-realistic, 8k, Blender Cycles style.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

