import { GoogleGenAI, Type } from "@google/genai";
import { CharacterParameters, MachineParameters, BiomechSyncData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Procesa los 3 inputs y genera la sincronización biomecánica final.
 * Implementa la regla: "El texto tiene prioridad sobre la imagen".
 */
export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `ACTÚA COMO UN ARQUITECTO DE SOFTWARE BIOMECÁNICO 3D.
  TU OBJETIVO: Sincronizar un Sujeto con una Máquina para el Ejercicio: "${exercise}".

  REGLAS CRÍTICAS:
  1. EL TEXTO TIENE PRIORIDAD: Si el usuario dice que el ejercicio es "${exercise}", ignora cualquier ruido visual en las imágenes que no coincida.
  2. BÚSQUEDA DE GROUNDING: Usa Google Search para validar la biomecánica real de la máquina y el ejercicio en sitios como Technogym, Life Fitness o estudios de kinesiología.
  3. SEGURIDAD: Identifica puntos de cizallamiento articular.

  INPUTS:
  - Sujeto: ${charInput.text || 'Basado en imagen'}
  - Máquina: ${machInput.text || 'Basado en imagen'}
  - Ejercicio Solicitado: ${exercise}

  RETORNA UN JSON ESTRICTO con la estructura definida para BiomechSync v3.0.`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
              validacion_biomecanica: { type: Type.STRING }
            },
            required: ['maquina_identificada', 'ejercicio_solicitado', 'validacion_biomecanica']
          },
          analisis_sujeto_maquina: {
            type: Type.OBJECT,
            properties: {
              alineacion_requerida: { type: Type.STRING },
              puntos_contacto_ik: {
                type: Type.OBJECT,
                properties: {
                  pecho: { type: Type.STRING },
                  caderas: { type: Type.STRING },
                  pies: { type: Type.STRING },
                  manos: { type: Type.STRING }
                },
                required: ['pecho', 'caderas', 'pies', 'manos']
              }
            },
            required: ['alineacion_requerida', 'puntos_contacto_ik']
          },
          logica_movimiento: {
            type: Type.OBJECT,
            properties: {
              fases: {
                type: Type.OBJECT,
                properties: {
                  concentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  },
                  excentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  }
                },
                required: ['concentrica', 'excentrica']
              },
              eficiencia_profesional: { type: Type.STRING }
            },
            required: ['fases', 'eficiencia_profesional']
          },
          output_rig_blender: {
            type: Type.OBJECT,
            properties: {
              nombre_animacion: { type: Type.STRING },
              fps: { type: Type.NUMBER },
              bindings: {
                type: Type.OBJECT,
                properties: {
                  chest_pad_constraint: { type: Type.STRING },
                  hip_pivot_lock: { type: Type.STRING },
                  feet_roller_ik: { type: Type.STRING },
                  hands_handle_target: { type: Type.STRING }
                },
                required: ['chest_pad_constraint', 'hip_pivot_lock', 'feet_roller_ik', 'hands_handle_target']
              },
              notas_seguridad: { type: Type.STRING }
            },
            required: ['nombre_animacion', 'fps', 'bindings', 'notas_seguridad']
          }
        },
        required: ['verificacion_grounding', 'analisis_sujeto_maquina', 'logica_movimiento', 'output_rig_blender']
      }
    }
  });

  const sources: { title: string; uri: string }[] = [];
  response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any) => {
    if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
  });

  return { data: JSON.parse(response.text), sources };
};

export const generateVisualV3 = async (sync: BiomechSyncData): Promise<string> => {
  const prompt = `A highly technical 3D biomechanical visualization of the exercise "${sync.verificacion_grounding.ejercicio_solicitado}" using a ${sync.verificacion_grounding.maquina_identificada}. 
  The image must show a generic 3D human model (muscular, mesh visible) perfectly aligned with the machine. 
  Cyberpunk HUD overlay, showing pivot points in red/green circles. Articular axis lines clearly visible. 
  Hyper-realistic, laboratory environment, Unreal Engine 5 render style, 8k.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

