const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Motor de Sincronización Biomecánica v3.1
 * Prioriza el texto sobre la imagen y utiliza búsqueda web para validar la biomecánica.
 */
export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `SISTEMA DE SINCRONIZACIÓN BIOMECÁNICA v3.1 - MODO PRIORIDAD DE TEXTO.

  OBJETIVO: Sincronizar un Sujeto con una Máquina para el Ejercicio exacto: "${exercise}".

  REGLAS DE ORO:
  1. EL TEXTO ES LEY: Si el usuario especifica "${exercise}", genera la lógica para ese ejercicio aunque la imagen de la máquina parezca otra cosa.
  2. GROUNDING OBLIGATORIO: Busca en Technogym, Life Fitness y manuales de kinesiología para el ejercicio "${exercise}".
  3. DESCRIPCIÓN IK: Define con precisión milimétrica dónde va cada articulación (pivotes).

  ENTRADAS:
  - Sujeto: ${charInput.text || 'Humanoide estándar'}
  - Descripción Máquina (Texto): ${machInput.text || 'Inferir de ejercicio'}
  - Ejercicio Solicitado: ${exercise}

  RETORNA UN JSON CON LA ESTRUCTURA ESPECIFICADA.`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview', // Upgrade a Pro para razonamiento complejo
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
