    visualUrl: null,
    isAnalyzing: false,
  });

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>, type: 'char' | 'mach') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'char') setCharImg(reader.result as string);
        else setMachImg(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const runSyncV3 = async () => {
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const fullExerciseName = `${exercise} ${variant}`;
      const { data, sources } = await gemini.runBiomechSyncV3(
        { image: charImg || undefined, text: charDesc },
        { image: machImg || undefined, text: machDesc },
        fullExerciseName
      );
      const visual = await gemini.generateVisualV3(data);

      setState({
        syncData: data,
        groundingSources: sources,
        visualUrl: visual,
        isAnalyzing: false
      });
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
      alert("Error en la sincronización biomecánica.");
    }
  };

  const downloadProject = () => {
    if (!state.syncData) return;
    const blob = new Blob([JSON.stringify(state.syncData, null, 2)], { type: 'application/json' });
