import { GoogleGenAI, Type } from "@google/genai";
import { BiomechSyncData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Motor de Sincronización Biomecánica v3.2 - Especialista en Máquinas
 * Actúa como un experto en ingeniería de gimnasio y kinesiología.
 */
export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `ACTÚA COMO UN ESPECIALISTA TÉCNICO EN MÁQUINAS DE GIMNASIO Y BIOMECÁNICA APLICADA AL RIGGING 3D.

  TU MISIÓN: Descomponer la interacción entre un sujeto y una máquina para el ejercicio: "${exercise}".

  REGLAS CRÍTICAS DE ESPECIALISTA:
  1. IDENTIFICACIÓN DE MÁQUINA: Analiza la imagen/texto de la máquina. Identifica el eje de rotación (pivot point), las almohadillas de apoyo (pads) y los terminales de fuerza (donde se aplica el empuje/tracción).
  2. MAPA DE APOYOS: Define exactamente dónde se sitúa cada parte del cuerpo:
     - APOYO TORÁCICO: ¿Dónde descansa el pecho/espalda?
     - PIVOTE ARTICULAR: ¿Con qué parte de la máquina debe alinearse la articulación principal (ej: rodilla con el eje del curl)?
     - EXTREMIDADES: Posición exacta de manos y pies respecto a los rodillos/agarres.
  3. PRIORIDAD DE TEXTO: Si el usuario dice "${exercise}", el análisis DEBE corresponder a ese ejercicio, corrigiendo cualquier error visual de la máquina de entrada si es necesario.
  4. SEGURIDAD: Identifica riesgos de hiperextensión o cizallamiento.

  ENTRADAS:
  - Sujeto: ${charInput.text || 'Humanoide estándar'}
  - Máquina Ref: ${machInput.text || 'Basada en imagen'}
  - Ejercicio: ${exercise}

  RETORNA UN JSON ESTRICTO CON ESTOS PARÁMETROS PARA RIGGING PROFESIONAL.`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
              validacion_biomecanica: { type: Type.STRING }
            },
            required: ['maquina_identificada', 'ejercicio_solicitado', 'validacion_biomecanica']
          },
          analisis_sujeto_maquina: {
            type: Type.OBJECT,
            properties: {
              alineacion_requerida: { type: Type.STRING },
              puntos_contacto_ik: {
                type: Type.OBJECT,
                properties: {
                  pecho: { type: Type.STRING },
                  caderas: { type: Type.STRING },
                  pies: { type: Type.STRING },
                  manos: { type: Type.STRING }
                },
                required: ['pecho', 'caderas', 'pies', 'manos']
              }
            },
            required: ['alineacion_requerida', 'puntos_contacto_ik']
          },
          logica_movimiento: {
            type: Type.OBJECT,
            properties: {
              fases: {
                type: Type.OBJECT,
                properties: {
                  concentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  },
                  excentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  }
                },
                required: ['concentrica', 'excentrica']
              },
              eficiencia_profesional: { type: Type.STRING }
            },
            required: ['fases', 'eficiencia_profesional']
          },
          output_rig_blender: {
            type: Type.OBJECT,
            properties: {
              nombre_animacion: { type: Type.STRING },
              fps: { type: Type.NUMBER },
              bindings: {
                type: Type.OBJECT,
                properties: {
                  chest_pad_constraint: { type: Type.STRING },
                  hip_pivot_lock: { type: Type.STRING },
                  feet_roller_ik: { type: Type.STRING },
                  hands_handle_target: { type: Type.STRING }
                },
                required: ['chest_pad_constraint', 'hip_pivot_lock', 'feet_roller_ik', 'hands_handle_target']
              },
              notas_seguridad: { type: Type.STRING }
            },
            required: ['nombre_animacion', 'fps', 'bindings', 'notas_seguridad']
          }
        },
        required: ['verificacion_grounding', 'analisis_sujeto_maquina', 'logica_movimiento', 'output_rig_blender']
      }
    }
  });

  const sources: { title: string; uri: string }[] = [];
  response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any) => {
    if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
  });

  return { data: JSON.parse(response.text), sources };
};

export const generateVisualV3 = async (sync: BiomechSyncData): Promise<string> => {
  // Prompt técnico forzado basado en la identificación previa del especialista
  const prompt = `A professional biomechanical 3D simulation of ${sync.verificacion_grounding.ejercicio_solicitado}.
  MACHINE SPECIALIST PARAMETERS:
  - Base Machine: ${sync.verificacion_grounding.maquina_identificada}
  - Joint Alignment: ${sync.analisis_sujeto_maquina.alineacion_requerida}
  - Body Mapping: Chest on ${sync.analisis_sujeto_maquina.puntos_contacto_ik.pecho}, Hips at ${sync.analisis_sujeto_maquina.puntos_contacto_ik.caderas}, Hands at ${sync.analisis_sujeto_maquina.puntos_contacto_ik.manos}, Feet at ${sync.analisis_sujeto_maquina.puntos_contacto_ik.pies}.
  VISUAL STYLE: Hyper-realistic 3D rendering with wireframe overlays. Laboratory setting. Glowing red pivot point indicators. Joint axis lines in neon green. 8k Unreal Engine 5 style. Ensure the exercise matches the text: ${sync.verificacion_grounding.ejercicio_solicitado}.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

