import { GoogleGenAI, Type } from "@google/genai";
import { BiomechSyncData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Motor de Sincronización Biomecánica v3.4 - Especialista en Fusión Espacial
 * Diseñado para situar al sujeto exactamente en la posición de uso de la máquina.
 */
export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `ACTÚA COMO UN INGENIERO DE SIMULACIÓN BIOMECÁNICA Y ESPECIALISTA EN RIGGING DE MÁQUINAS.

  TU OBJETIVO: Generar el "Blueprint de Montaje" exacto para situar a un sujeto DENTRO de la máquina para el ejercicio: "${exercise}".

  INSTRUCCIONES DE MAPEO TÉCNICO:
  1. IDENTIFICACIÓN DE GEOMETRÍA: Analiza la máquina y determina su posición de uso estándar (tumbado, sentado, de pie).
  2. INTEGRACIÓN FÍSICA: Define cómo el sujeto se acopla a la máquina:
     - El Pecho DEBE estar en contacto con: [Identificar almohadilla].
     - Las Manos DEBEN asir: [Identificar manerales].
     - Los Pies DEBEN estar bloqueados por: [Identificar rodillo/plataforma].
     - Las Caderas DEBEN pivotar en: [Identificar eje].
  3. COHERENCIA DE EJERCICIO: Si el ejercicio es "${exercise}", la posición del cuerpo DEBE ser la reglamentaria para dicho movimiento, ignorando cualquier pose previa del sujeto.
  4. ALINEACIÓN DE PIVOTES: El eje de rotación de la máquina debe ser idéntico al eje de rotación de la articulación del sujeto.

  INPUTS:
  - Sujeto: ${charInput.text || 'Humanoide anatómico'}
  - Máquina: ${machInput.text || 'Basada en visual'}
  - Ejercicio: ${exercise}

  RETORNA UN JSON ESTRICTO PARA MAPEO ESPACIAL.`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
              validacion_biomecanica: { type: Type.STRING }
            },
            required: ['maquina_identificada', 'ejercicio_solicitado', 'validacion_biomecanica']
          },
          analisis_sujeto_maquina: {
            type: Type.OBJECT,
            properties: {
              alineacion_requerida: { type: Type.STRING },
              puntos_contacto_ik: {
                type: Type.OBJECT,
                properties: {
                  pecho: { type: Type.STRING },
                  caderas: { type: Type.STRING },
                  pies: { type: Type.STRING },
                  manos: { type: Type.STRING }
                },
                required: ['pecho', 'caderas', 'pies', 'manos']
              }
            },
            required: ['alineacion_requerida', 'puntos_contacto_ik']
          },
          logica_movimiento: {
            type: Type.OBJECT,
            properties: {
              fases: {
                type: Type.OBJECT,
                properties: {
                  concentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  },
                  excentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  }
                },
                required: ['concentrica', 'excentrica']
              },
              eficiencia_profesional: { type: Type.STRING }
            },
            required: ['fases', 'eficiencia_profesional']
          },
          output_rig_blender: {
            type: Type.OBJECT,
            properties: {
              nombre_animacion: { type: Type.STRING },
              fps: { type: Type.NUMBER },
              bindings: {
                type: Type.OBJECT,
                properties: {
                  chest_pad_constraint: { type: Type.STRING },
                  hip_pivot_lock: { type: Type.STRING },
                  feet_roller_ik: { type: Type.STRING },
                  hands_handle_target: { type: Type.STRING }
                },
                required: ['chest_pad_constraint', 'hip_pivot_lock', 'feet_roller_ik', 'hands_handle_target']
              },
              notas_seguridad: { type: Type.STRING }
            },
            required: ['nombre_animacion', 'fps', 'bindings', 'notas_seguridad']
          }
        },
        required: ['verificacion_grounding', 'analisis_sujeto_maquina', 'logica_movimiento', 'output_rig_blender']
      }
    }
  });

  const sources: { title: string; uri: string }[] = [];
  response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any) => {
    if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
  });

  return { data: JSON.parse(response.text), sources };
};

export const generateVisualV3 = async (sync: BiomechSyncData): Promise<string> => {
  const prompt = `A professional biomechanical 3D scene of the exercise "${sync.verificacion_grounding.ejercicio_solicitado}". 
  ULTRA-STRICT SPATIAL FUSION:
  - The humanoid is PHYSICALLY INTEGRATED into the ${sync.verificacion_grounding.maquina_identificada}. 
  - CONTACT POINTS: Hands are firmly grasping ${sync.analisis_sujeto_maquina.puntos_contacto_ik.manos}. Feet are correctly placed on ${sync.analisis_sujeto_maquina.puntos_contacto_ik.pies}. Hips are locked at ${sync.analisis_sujeto_maquina.puntos_contacto_ik.caderas}. Chest is supported by ${sync.analisis_sujeto_maquina.puntos_contacto_ik.pecho}.
  - ALIGNMENT: The humanoid's main joint axis is PERFECTLY ALIGNED with the machine's mechanical pivot point (${sync.analisis_sujeto_maquina.alineacion_requerida}).
  VISUAL STYLE: Hyper-realistic 3D render, technical wireframe overlay, red circle indicators for pivot points, green vector lines for movement paths. Laboratory clean environment, Unreal Engine 5 quality, 8k. The scene must look like a high-end engineering simulation.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

