import { GoogleGenAI, Type } from "@google/genai";
import { BiomechSyncData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Motor de Sincronización Biomecánica v3.5 - Especialista en Dinámica Cinética
 * Analiza trayectorias curvas, centros de rotación y perfiles de velocidad.
 */
export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `ACTÚA COMO UN INGENIERO DE DINÁMICA CINÉTICA Y FÍSICA APLICADA AL DEPORTE.

  OBJETIVO: Realizar un análisis dinámico completo del ejercicio: "${exercise}" integrando al sujeto en la máquina.

  ESPECIFICACIONES DE DINÁMICA OBLIGATORIAS:
  1. TRAYECTORIA CURVA: Define el arco de movimiento. No es lineal. Describe el radio y el ángulo de la curva que sigue el rodillo/agarre.
  2. CENTRO DE ROTACIÓN: Identifica el punto de pivote exacto de la máquina. El eje articular del usuario DEBE coincidir con este centro.
  3. RELACIÓN CARGA-CUERPO: Describe la presión dinámica entre el componente de la máquina (ej: rodillo) y la extremidad (ej: tibia/femoral).
  4. TIMING Y ACELERACIÓN: Define el perfil de velocidad (ej: inicio explosivo, tensión constante en el pico, frenado excéntrico progresivo).

  INPUTS:
  - Sujeto: ${charInput.text || 'Basado en imagen'}
  - Máquina: ${machInput.text || 'Basada en imagen'}
  - Ejercicio: ${exercise}

  RETORNA UN JSON ESTRICTO INCLUYENDO EL NUEVO CAMPO "mapeo_dinamico".`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
              validacion_biomecanica: { type: Type.STRING }
            },
            required: ['maquina_identificada', 'ejercicio_solicitado', 'validacion_biomecanica']
          },
          analisis_sujeto_maquina: {
            type: Type.OBJECT,
            properties: {
              alineacion_requerida: { type: Type.STRING },
              puntos_contacto_ik: {
                type: Type.OBJECT,
                properties: {
                  pecho: { type: Type.STRING },
                  caderas: { type: Type.STRING },
                  pies: { type: Type.STRING },
                  manos: { type: Type.STRING }
                },
                required: ['pecho', 'caderas', 'pies', 'manos']
              }
            },
            required: ['alineacion_requerida', 'puntos_contacto_ik']
          },
          mapeo_dinamico: {
            type: Type.OBJECT,
            properties: {
              trayectoria_arco: { type: Type.STRING },
              relacion_rodillo_extremidad: { type: Type.STRING },
              centro_rotacion_mecanico: { type: Type.STRING },
              perfil_timing: { type: Type.STRING }
            },
            required: ['trayectoria_arco', 'relacion_rodillo_extremidad', 'centro_rotacion_mecanico', 'perfil_timing']
          },
          logica_movimiento: {
            type: Type.OBJECT,
            properties: {
              fases: {
                type: Type.OBJECT,
                properties: {
                  concentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  },
                  excentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  }
                },
                required: ['concentrica', 'excentrica']
              },
              eficiencia_profesional: { type: Type.STRING }
            },
            required: ['fases', 'eficiencia_profesional']
          },
          output_rig_blender: {
            type: Type.OBJECT,
            properties: {
              nombre_animacion: { type: Type.STRING },
