export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `ACTÚA COMO UN INGENIERO DE SIMULACIÓN BIOMECÁNICA.

  TU MISIÓN: Analizar el ejercicio "${exercise}" para generar una simulación de ejecución perfecta utilizando LA MÁQUINA ESPECÍFICA de la imagen.

  REGLAS DE ANÁLISIS DINÁMICO:
  1. IDENTIFICACIÓN DE COMPONENTES: Detecta los ejes de rotación, los brazos de palanca y los puntos de apoyo de LA MÁQUINA PROPORCIONADA.
  2. MAPEO DE CONTACTO: Define la posición exacta de manos, pies, caderas y pecho para que el sujeto esté integrado mecánicamente en esa estructura específica.
  3. DINÁMICA DE ARCO: Calcula la trayectoria curva del movimiento basada en el brazo de palanca real de esa máquina. El pivote de la máquina debe coincidir con el eje articular del sujeto.
  4. PERFIL DE MOVIMIENTO: Describe la fase de máxima contracción para la imagen final.

  INPUTS:
  - Sujeto: ${charInput.text || 'Basado en imagen'}
  - Máquina: ${machInput.text || 'Basada en imagen'}
  - Ejercicio: ${exercise}

  RETORNA UN JSON ESTRICTO CON TODOS LOS PARÁMETROS PARA RIGGING Y ANIMACIÓN.`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
              validacion_biomecanica: { type: Type.STRING }
            },
            required: ['maquina_identificada', 'ejercicio_solicitado', 'validacion_biomecanica']
          },
          analisis_sujeto_maquina: {
            type: Type.OBJECT,
            properties: {
              alineacion_requerida: { type: Type.STRING },
              puntos_contacto_ik: {
                type: Type.OBJECT,
                properties: {
                  pecho: { type: Type.STRING },
                  caderas: { type: Type.STRING },
                  pies: { type: Type.STRING },
                  manos: { type: Type.STRING }
                },
                required: ['pecho', 'caderas', 'pies', 'manos']
              }
            },
            required: ['alineacion_requerida', 'puntos_contacto_ik']
          },
          mapeo_dinamico: {
            type: Type.OBJECT,
            properties: {
              trayectoria_arco: { type: Type.STRING },
              relacion_rodillo_extremidad: { type: Type.STRING },
              centro_rotacion_mecanico: { type: Type.STRING },
              perfil_timing: { type: Type.STRING }
            },
            required: ['trayectoria_arco', 'relacion_rodillo_extremidad', 'centro_rotacion_mecanico', 'perfil_timing']
          },
          logica_movimiento: {
            type: Type.OBJECT,
            properties: {
              fases: {
                type: Type.OBJECT,
                properties: {
                  concentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  },
                  excentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  }
                },
                required: ['concentrica', 'excentrica']
              },
              eficiencia_profesional: { type: Type.STRING }
            },
            required: ['fases', 'eficiencia_profesional']
          },
          output_rig_blender: {
            type: Type.OBJECT,
            properties: {
              nombre_animacion: { type: Type.STRING },
              fps: { type: Type.NUMBER },
              bindings: {
                type: Type.OBJECT,
                properties: {
                  chest_pad_constraint: { type: Type.STRING },
                  hip_pivot_lock: { type: Type.STRING },
                  feet_roller_ik: { type: Type.STRING },
                  hands_handle_target: { type: Type.STRING }
                },
                required: ['chest_pad_constraint', 'hip_pivot_lock', 'feet_roller_ik', 'hands_handle_target']
              },
              notas_seguridad: { type: Type.STRING }
            },
            required: ['nombre_animacion', 'fps', 'bindings', 'notas_seguridad']
          }
        },
        required: ['verificacion_grounding', 'analisis_sujeto_maquina', 'mapeo_dinamico', 'logica_movimiento', 'output_rig_blender']
      }
    }
  });

  const sources: { title: string; uri: string }[] = [];
  response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any) => {
    if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
  });

  return { data: JSON.parse(response.text), sources };
};

export const generateVisualV3 = async (sync: BiomechSyncData, machineImageBase64?: string): Promise<string> => {
  const prompt = `EXACT REPLICATION AND FUSION TASK:

  1. BASE MACHINE: Use the EXACT machine structure, color, and mechanical components from the provided machine reference image. Do not use generic gym equipment. Replicate the padding, levers, and frame accurately.

  2. SUBJECT INTEGRATION: Place a professional 3D humanoid subject PERFORMING THE ${sync.verificacion_grounding.ejercicio_solicitado} on this EXACT machine.

  3. SPATIAL POSITIONING: 
     - Hands must grasp the original machine's handles.
     - Feet must be locked under the machine's rollers as described: ${sync.analisis_sujeto_maquina.puntos_contacto_ik.pies}.
     - The subject's joint axis must align with the machine's actual pivot point.

  4. EXECUTION SHOT: Mid-repetition with clear tension and force vectors visible as subtle neon arcs (${sync.mapeo_dinamico.trayectoria_arco}).

  VISUAL STYLE: Hyper-clean 3D engineering simulation. Neutral studio background. Professional CGI lighting. 8k. High anatomical fidelity.`;

  const contents: any[] = [{ text: prompt }];

  // Enviamos la imagen de la máquina original como entrada para que la IA la replique
  if (machineImageBase64) {
    contents.push({
      inlineData: {
        data: machineImageBase64.split(',')[1],
        mimeType: 'image/jpeg',
      },
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: contents },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

