export const generateVisualV3 = async (sync: BiomechSyncData, machineImageBase64?: string): Promise<string> => {
  const prompt = `PHYSICAL COHERENCE REPLICA TASK:

  1. BASE MACHINE REPLICATION: Use the EXACT machine structure from the reference image.

  2. MECHANICAL CONTINUITY (CRITICAL): There must be a SOLID METAL BRAZO MECÁNICO (LEVER ARM) clearly visible connecting the pivot point to the rollers/handles. 
     - NO FLOATING ROLLERS: The roller must be physically attached to the machine's frame via a structural arm.
     - Visualize the hinge and the lever clearly. The weight is transmitted through this visible metal structure.

  3. SUBJECT FUSION: Place the humanoid PERFORMING THE ${sync.verificacion_grounding.ejercicio_solicitado}.
     - The subject's heels must be firmly in contact with the roller.
     - The arm connecting the roller to the machine must be positioned according to the dynamic arc: ${sync.mapeo_dinamico.trayectoria_arco}.

  4. SPATIAL POSITIONING: 
     - Align the subject's joint pivot with the machine's mechanical pivot axis (${sync.mapeo_dinamico.centro_rotacion_mecanico}).

  VISUAL STYLE: Hyper-clean 3D engineering simulation. Professional CGI. 8k. White background. Ensure all mechanical links are logically rendered and connected.`;

  const contents: any[] = [{ text: prompt }];

  if (machineImageBase64) {
    contents.push({
      inlineData: {
        data: machineImageBase64.split(',')[1],
        mimeType: 'image/jpeg',
      },
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: contents },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

