import { GoogleGenAI, Type } from "@google/genai";
import { BiomechSyncData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

/**
 * Motor de Sincronización Biomecánica v3.9 - Blender Export Edition
 * Genera especificaciones técnicas de Rigging para exportación a formato FBX/Blender.
 */
export const runBiomechSyncV3 = async (
  charInput: { image?: string; text?: string },
  machInput: { image?: string; text?: string },
  exercise: string
): Promise<{ data: BiomechSyncData; sources: { title: string; uri: string }[] }> => {

  const prompt = `ACTÚA COMO UN INGENIERO DE RIGGING 3D Y EXPERTO EN BLENDER.

  TU MISIÓN: Analizar el ejercicio "${exercise}" y la máquina de la imagen para crear un RIG COMPLETO listo para Blender.

  REGLAS DE EXPORTACIÓN 3D:
  1. ARMATURE NODES: Define las posiciones (X, Y, Z) de los huesos principales del sujeto en relación al pivote de la máquina.
  2. CONSTRAINTS DE BLENDER: Define qué huesos deben tener un 'Limit Rotation' o 'Track To' basado en el movimiento mecánico.
  3. BRAZO MECÁNICO (LEVER): Describe el objeto 'Empty' que servirá como controlador del brazo de palanca de la máquina.
  4. COHERENCIA FÍSICA: Asegura que el rodillo esté conectado al brazo y el brazo al pivote mediante una jerarquía de parentesco (Parenting).

  INPUTS:
  - Sujeto: ${charInput.text || 'Basado en imagen'}
  - Máquina: ${machInput.text || 'Réplica exacta de imagen'}
  - Ejercicio: ${exercise}

  RETORNA UN JSON ESTRICTO CON PARÁMETROS DE RIGGING PARA BLENDER.`;

  const contents: any[] = [{ text: prompt }];

  if (charInput.image) {
    contents.push({ inlineData: { data: charInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }
  if (machInput.image) {
    contents.push({ inlineData: { data: machInput.image.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          verificacion_grounding: {
            type: Type.OBJECT,
            properties: {
              maquina_identificada: { type: Type.STRING },
              ejercicio_solicitado: { type: Type.STRING },
              validacion_biomecanica: { type: Type.STRING }
            },
            required: ['maquina_identificada', 'ejercicio_solicitado', 'validacion_biomecanica']
          },
          analisis_sujeto_maquina: {
            type: Type.OBJECT,
            properties: {
              alineacion_requerida: { type: Type.STRING },
              puntos_contacto_ik: {
                type: Type.OBJECT,
                properties: {
                  pecho: { type: Type.STRING },
                  caderas: { type: Type.STRING },
                  pies: { type: Type.STRING },
                  manos: { type: Type.STRING }
                },
                required: ['pecho', 'caderas', 'pies', 'manos']
              }
            },
            required: ['alineacion_requerida', 'puntos_contacto_ik']
          },
          mapeo_dinamico: {
            type: Type.OBJECT,
            properties: {
              trayectoria_arco: { type: Type.STRING },
              relacion_rodillo_extremidad: { type: Type.STRING },
              centro_rotacion_mecanico: { type: Type.STRING },
              perfil_timing: { type: Type.STRING }
            },
            required: ['trayectoria_arco', 'relacion_rodillo_extremidad', 'centro_rotacion_mecanico', 'perfil_timing']
          },
          logica_movimiento: {
            type: Type.OBJECT,
            properties: {
              fases: {
                type: Type.OBJECT,
                properties: {
                  concentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  },
                  excentrica: {
                    type: Type.OBJECT,
                    properties: {
                      accion: { type: Type.STRING },
                      rango_movimiento_grados: { type: Type.STRING },
                      respiracion: { type: Type.STRING }
                    },
                    required: ['accion', 'rango_movimiento_grados', 'respiracion']
                  }
                },
                required: ['concentrica', 'excentrica']
              },
              eficiencia_profesional: { type: Type.STRING }
            },
            required: ['fases', 'eficiencia_profesional']
          },
          output_rig_blender: {
            type: Type.OBJECT,
            properties: {
              nombre_animacion: { type: Type.STRING },
              fps: { type: Type.NUMBER },
              bindings: {
                type: Type.OBJECT,
                properties: {
                  chest_pad_constraint: { type: Type.STRING },
                  hip_pivot_lock: { type: Type.STRING },
                  feet_roller_ik: { type: Type.STRING },
                  hands_handle_target: { type: Type.STRING }
                },
                required: ['chest_pad_constraint', 'hip_pivot_lock', 'feet_roller_ik', 'hands_handle_target']
              },
              notas_seguridad: { type: Type.STRING }
            },
            required: ['nombre_animacion', 'fps', 'bindings', 'notas_seguridad']
          }
        },
        required: ['verificacion_grounding', 'analisis_sujeto_maquina', 'mapeo_dinamico', 'logica_movimiento', 'output_rig_blender']
      }
    }
  });

  const sources: { title: string; uri: string }[] = [];
  response.candidates?.[0]?.groundingMetadata?.groundingChunks?.forEach((chunk: any) => {
    if (chunk.web) sources.push({ title: chunk.web.title, uri: chunk.web.uri });
  });

  return { data: JSON.parse(response.text), sources };
};

export const generateVisualV3 = async (sync: BiomechSyncData, machineImageBase64?: string): Promise<string> => {
  const prompt = `BLENDER RENDER SPECIFICATION:

  1. MACHINE REPLICA: Accurate structure and colors from reference image.
  2. MECHANICAL CONNECTIVITY: VISIBLE METAL LEVER ARM connecting the pivot point axis to the rollers. NO FLOATING PARTS. The arm must be structural.
  3. RIGGING PREVIEW: Place the humanoid on the machine. Show the contact points (${sync.analisis_sujeto_maquina.puntos_contacto_ik.pies}) with professional anatomical precision.
  4. ALIGNMENT: Knee/Joint axis aligned with machine pivot (${sync.mapeo_dinamico.centro_rotacion_mecanico}).

  STYLE: Clean 3D studio simulation. Grey backdrop. 8k. Unreal Engine 5 high-fidelity style. All mechanical links must be logically connected.`;

  const contents: any[] = [{ text: prompt }];

  if (machineImageBase64) {
    contents.push({ inlineData: { data: machineImageBase64.split(',')[1], mimeType: 'image/jpeg' } });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: contents },
    config: { imageConfig: { aspectRatio: '16:9' } }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Visual generation failed.");
};

