export default function App() {
  const [charImg, setCharImg] = useState<string | null>(null);
  const [charDesc, setCharDesc] = useState('Humanoide anatómico');
  const [machImg, setMachImg] = useState<string | null>(null);
  const [machDesc, setMachDesc] = useState('');
  const [exercise, setExercise] = useState('CURL FEMORAL');

  const [state, setState] = useState<AnalysisState>({
    syncData: null,
    groundingSources: [],
    visualUrl: null,
    isAnalyzing: false,
  });

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>, type: 'char' | 'mach') => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (type === 'char') setCharImg(reader.result as string);
        else setMachImg(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const runSyncV3 = async () => {
    setState(prev => ({ ...prev, isAnalyzing: true }));
    try {
      const { data, sources } = await gemini.runBiomechSyncV3(
        { image: charImg || undefined, text: charDesc },
        { image: machImg || undefined, text: machDesc },
        exercise
      );

      const visual = await gemini.generateVisualV3(data, machImg || undefined);

      setState({
        syncData: data,
        groundingSources: sources,
        visualUrl: visual,
        isAnalyzing: false
      });
    } catch (error) {
      console.error(error);
      setState(prev => ({ ...prev, isAnalyzing: false }));
      alert("Error en la validación de coherencia mecánica.");
    }
  };

  const downloadFBX = () => {
    if (!state.syncData) return;
    const fbxContent = gemini.generateFBXFile(state.syncData);
    const blob = new Blob([fbxContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
