    link.href = url;
    link.download = `${state.syncData.verificacion_grounding.ejercicio_solicitado.replace(/\s+/g, '_')}_RIG.fbx`;
    link.click();
  };

  const downloadJSON = () => {
    if (!state.syncData) return;
    const blob = new Blob([JSON.stringify(state.syncData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `mechanical_coherence_v3.9.json`;
    link.click();
