                ].map((item, idx) => (
                  <div key={idx} className="p-8 rounded-[2.5rem] border border-white/5 bg-white/5 flex flex-col items-center text-center">
                    <item.icon className={`w-6 h-6 ${item.color} mb-4`} />
                    <span className="text-[10px] font-black uppercase text-slate-500 tracking-widest block mb-2">{item.label}</span>
                    <p className="text-[11px] font-bold text-slate-300 leading-tight">{item.val}</p>
                  </div>
                ))}
