            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="bg-[#080808] border border-white/5 rounded-[3rem] overflow-hidden flex flex-col shadow-2xl">
                <div className="px-10 py-8 border-b border-white/5 flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <Terminal className="w-5 h-5 text-orange-400" />
                    <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Blender_Rigging_Script_v3.9</span>
                  </div>
                </div>
                <div className="flex-1 p-10 font-mono text-[11px] text-slate-500 overflow-auto bg-[#030303] custom-scrollbar">
                  <pre className="selection:bg-orange-500/40">{JSON.stringify(state.syncData.output_rig_blender, null, 2)}</pre>
                </div>
              </div>

              <div className="space-y-8 flex flex-col justify-center">
                <div className="bg-emerald-500/5 border border-emerald-500/10 p-10 rounded-[3rem] flex items-start gap-8">
                  <ShieldCheck className="w-10 h-10 text-emerald-500 shrink-0" />
                  <div>
                    <h5 className="text-[10px] font-black uppercase text-emerald-500 tracking-[0.3em] mb-4">Export Status: Validated</h5>
                    <p className="text-sm text-slate-300 leading-relaxed font-bold italic">Se han generado los nodos 'Null' para el pivote y el brazo de palanca. Al importar el FBX en Blender, estos actuarán como controladores de la Armadura para replicar el movimiento mecánico de la máquina.</p>
                  </div>
                </div>

                <div className="bg-white/5 p-10 rounded-[3rem] border border-white/5">
                  <h6 className="text-[9px] font-black uppercase text-slate-500 tracking-widest mb-6">Rigging Hierarchy</h6>
                  <div className="space-y-4">
                    <div className="flex items-center justify-between text-[11px] font-bold">
                       <span className="text-slate-500">Parent: Machine_Base</span>
                       <span className="text-orange-400">Child: Pivot_Axis</span>
                    </div>
                    <div className="w-full h-px bg-white/5" />
                    <div className="flex items-center justify-between text-[11px] font-bold">
                       <span className="text-slate-500">Parent: Pivot_Axis</span>
                       <span className="text-orange-400">Child: Lever_Arm</span>
                    </div>
                    <div className="w-full h-px bg-white/5" />
                    <div className="flex items-center justify-between text-[11px] font-bold">
                       <span className="text-slate-500">Parent: Lever_Arm</span>
                       <span className="text-orange-400">Child: Roller_Constraint</span>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}
